import{_ as a,o as t,c as s,ag as l}from"./chunks/framework.DXGyWiRo.js";const h=JSON.parse('{"title":"Claude Projects功能深度使用教程：让AI记住你的一切","description":"2026年Claude Projects功能完整教程：如何创建项目、设置系统提示、上传知识库、跨对话保持记忆，彻底解锁Claude Pro最强功能。","frontmatter":{"title":"Claude Projects功能深度使用教程：让AI记住你的一切","description":"2026年Claude Projects功能完整教程：如何创建项目、设置系统提示、上传知识库、跨对话保持记忆，彻底解锁Claude Pro最强功能。","head":[["meta",{"name":"keywords","content":"Claude Projects,Claude项目功能,Claude记忆,Claude知识库,Claude系统提示,Claude Projects教程,Claude Pro功能,Claude长期记忆"}],["link",{"rel":"canonical","href":"https://claude-recharge.com/news/grok4-deepsearch-guide"}],["meta",{"property":"og:title","content":"Claude Projects功能深度使用教程：让AI记住你的一切"}],["meta",{"property":"og:description","content":"2026年Claude Projects功能完整教程：如何创建项目、设置系统提示、上传知识库、跨对话保持记忆，彻底解锁Claude Pro最强功能。"}],["meta",{"property":"og:url","content":"https://claude-recharge.com/news/grok4-deepsearch-guide"}],["script",{"type":"application/ld+json"},"{\\"@context\\":\\"https://schema.org\\",\\"@type\\":\\"Article\\",\\"headline\\":\\"Claude Projects功能深度使用教程：让AI记住你的一切\\",\\"description\\":\\"2026年Claude Projects功能完整教程：如何创建项目、设置系统提示、上传知识库、跨对话保持记忆，彻底解锁Claude Pro最强功能。\\",\\"datePublished\\":\\"2026-04-20T00:00:00.000Z\\",\\"dateModified\\":\\"2026-04-21T14:39:48.281Z\\",\\"author\\":{\\"@type\\":\\"Organization\\",\\"name\\":\\"Claude代充平台\\",\\"url\\":\\"https://claude-recharge.com\\"},\\"publisher\\":{\\"@type\\":\\"Organization\\",\\"name\\":\\"Claude代充平台\\",\\"url\\":\\"https://claude-recharge.com\\"},\\"mainEntityOfPage\\":{\\"@type\\":\\"WebPage\\",\\"@id\\":\\"https://claude-recharge.com/news/grok4-deepsearch-guide\\"},\\"inLanguage\\":\\"zh-CN\\"}"]],"date":"2026-04-20T00:00:00.000Z"},"headers":[],"relativePath":"news/grok4-deepsearch-guide.md","filePath":"news/grok4-deepsearch-guide.md","lastUpdated":null}'),o={name:"news/grok4-deepsearch-guide.md"};function r(n,e,i,p,c,d){return t(),s("div",null,[...e[0]||(e[0]=[l(`<h1 id="claude-projects功能深度使用教程-让ai记住你的一切" tabindex="-1">Claude Projects功能深度使用教程：让AI记住你的一切 <a class="header-anchor" href="#claude-projects功能深度使用教程-让ai记住你的一切" aria-label="Permalink to &quot;Claude Projects功能深度使用教程：让AI记住你的一切&quot;">​</a></h1><blockquote><p>最后更新：2026年4月20日</p></blockquote><p>Claude Projects是Pro及以上订阅用户独享的核心功能，它让Claude能够&quot;记住&quot;你的工作背景、偏好和知识库，实现真正的持续合作。本文是最完整的Projects使用指南。</p><hr><h2 id="一、projects是什么-解决了什么问题" tabindex="-1">一、Projects是什么？解决了什么问题？ <a class="header-anchor" href="#一、projects是什么-解决了什么问题" aria-label="Permalink to &quot;一、Projects是什么？解决了什么问题？&quot;">​</a></h2><p><strong>普通对话的痛点</strong>：</p><p>每次开始新对话，Claude对你一无所知：</p><ul><li>不知道你是做什么工作的</li><li>不记得上次讨论的内容</li><li>需要每次重新说明背景</li><li>每次都要重新上传参考文件</li></ul><p><strong>Projects的解决方案</strong>：</p><p>Projects是一个持久的工作空间，它包含：</p><ul><li><strong>系统提示</strong>：告诉Claude&quot;你是谁、你的工作是什么&quot;</li><li><strong>知识库</strong>：上传文件，Claude永久记住这些内容</li><li><strong>对话历史</strong>：在同一Project内，历史对话可以随时回溯</li></ul><hr><h2 id="二、如何创建和配置project" tabindex="-1">二、如何创建和配置Project？ <a class="header-anchor" href="#二、如何创建和配置project" aria-label="Permalink to &quot;二、如何创建和配置Project？&quot;">​</a></h2><h3 id="_2-1-创建project" tabindex="-1">2.1 创建Project <a class="header-anchor" href="#_2-1-创建project" aria-label="Permalink to &quot;2.1 创建Project&quot;">​</a></h3><ol><li>登录 claude.ai（需要Pro或Max订阅）</li><li>左侧侧边栏找到 <strong>&quot;Projects&quot;</strong></li><li>点击 <strong>&quot;+ New Project&quot;</strong></li><li>为项目命名（如&quot;内容创作助手&quot;、&quot;代码开发&quot;）</li></ol><h3 id="_2-2-设置系统提示-最关键步骤" tabindex="-1">2.2 设置系统提示（最关键步骤） <a class="header-anchor" href="#_2-2-设置系统提示-最关键步骤" aria-label="Permalink to &quot;2.2 设置系统提示（最关键步骤）&quot;">​</a></h3><p>进入Project后，点击 <strong>&quot;Project Instructions&quot;</strong> 设置系统提示。</p><p><strong>什么是好的系统提示？</strong></p><p>好的系统提示让Claude在每次对话前就了解你的背景，减少重复说明。</p><p><strong>示例系统提示（内容创作者）：</strong></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>你是我的内容创作助手。我是一名专注于AI工具评测的自媒体作者，主要在知乎和微信公众号发布内容，目标读者是科技爱好者和职场人士。</span></span>
<span class="line"><span></span></span>
<span class="line"><span>写作风格要求：</span></span>
<span class="line"><span>- 语言口语化，像在和朋友解释一样</span></span>
<span class="line"><span>- 多用具体例子，少用抽象描述</span></span>
<span class="line"><span>- 每篇文章要有清晰的行动建议</span></span>
<span class="line"><span></span></span>
<span class="line"><span>当我说&quot;帮我写&quot;时，直接输出成品，不要问太多问题。</span></span>
<span class="line"><span>当我说&quot;帮我想&quot;时，给出多个方案供我选择。</span></span></code></pre></div><p><strong>示例系统提示（开发者）：</strong></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>你是我的编程助手，专注于Python后端开发。我的技术栈：</span></span>
<span class="line"><span>- 后端：Python 3.11，FastAPI，SQLAlchemy</span></span>
<span class="line"><span>- 数据库：PostgreSQL，Redis</span></span>
<span class="line"><span>- 部署：Docker，AWS</span></span>
<span class="line"><span></span></span>
<span class="line"><span>代码要求：</span></span>
<span class="line"><span>- 遵循PEP 8风格</span></span>
<span class="line"><span>- 重要逻辑必须有注释</span></span>
<span class="line"><span>- 考虑异常处理</span></span>
<span class="line"><span>- 生产环境代码要有日志</span></span>
<span class="line"><span></span></span>
<span class="line"><span>直接给出完整可运行的代码，不需要解释每一行。</span></span></code></pre></div><h3 id="_2-3-上传知识库文件" tabindex="-1">2.3 上传知识库文件 <a class="header-anchor" href="#_2-3-上传知识库文件" aria-label="Permalink to &quot;2.3 上传知识库文件&quot;">​</a></h3><p>在Project中点击 <strong>&quot;Add files&quot;</strong>，可以上传：</p><table tabindex="0"><thead><tr><th style="text-align:left;">文件类型</th><th style="text-align:left;">使用场景</th></tr></thead><tbody><tr><td style="text-align:left;">PDF文档</td><td style="text-align:left;">行业报告、研究论文、产品手册</td></tr><tr><td style="text-align:left;">Word/TXT</td><td style="text-align:left;">品牌手册、写作规范、需求文档</td></tr><tr><td style="text-align:left;">代码文件</td><td style="text-align:left;">项目代码库、API文档</td></tr><tr><td style="text-align:left;">CSV/Excel</td><td style="text-align:left;">数据集、用户调研结果</td></tr><tr><td style="text-align:left;">图片</td><td style="text-align:left;">设计稿、截图（需图像理解）</td></tr></tbody></table><p><strong>文件大小限制</strong>：单个文件最大30MB，Project总容量200MB</p><hr><h2 id="三、projects的高效使用场景" tabindex="-1">三、Projects的高效使用场景 <a class="header-anchor" href="#三、projects的高效使用场景" aria-label="Permalink to &quot;三、Projects的高效使用场景&quot;">​</a></h2><h3 id="场景1-个人知识助手" tabindex="-1">场景1：个人知识助手 <a class="header-anchor" href="#场景1-个人知识助手" aria-label="Permalink to &quot;场景1：个人知识助手&quot;">​</a></h3><p>为自己的专业领域创建一个&quot;知识库项目&quot;：</p><ul><li>上传你最重要的行业报告（PDF格式）</li><li>设置系统提示说明你的专业背景</li><li>之后所有专业问题都在这个Project里问，Claude结合你的知识库回答</li></ul><h3 id="场景2-内容创作工厂" tabindex="-1">场景2：内容创作工厂 <a class="header-anchor" href="#场景2-内容创作工厂" aria-label="Permalink to &quot;场景2：内容创作工厂&quot;">​</a></h3><p><strong>创建多个专职Projects</strong>：</p><ul><li>&quot;选题策略&quot;Project：专门讨论内容方向</li><li>&quot;文章写作&quot;Project：专门撰写正文</li><li>&quot;标题优化&quot;Project：专门打磨标题和摘要</li></ul><p>每个Project设置对应的系统提示和参考资料，工作流程化，质量稳定。</p><h3 id="场景3-代码项目管理" tabindex="-1">场景3：代码项目管理 <a class="header-anchor" href="#场景3-代码项目管理" aria-label="Permalink to &quot;场景3：代码项目管理&quot;">​</a></h3><p>为每个代码项目创建独立Project：</p><ul><li>上传README和主要代码文件</li><li>在系统提示中说明技术规范</li><li>同一项目的所有对话都在这里，Claude始终记得项目背景</li></ul><h3 id="场景4-客户服务知识库" tabindex="-1">场景4：客户服务知识库 <a class="header-anchor" href="#场景4-客户服务知识库" aria-label="Permalink to &quot;场景4：客户服务知识库&quot;">​</a></h3><ul><li>上传产品文档、FAQ、价格表</li><li>系统提示说明服务规范和话术要求</li><li>在Project中处理客户咨询，回答精准一致</li></ul><hr><h2 id="四、projects管理技巧" tabindex="-1">四、Projects管理技巧 <a class="header-anchor" href="#四、projects管理技巧" aria-label="Permalink to &quot;四、Projects管理技巧&quot;">​</a></h2><h3 id="_4-1-给project分类命名" tabindex="-1">4.1 给Project分类命名 <a class="header-anchor" href="#_4-1-给project分类命名" aria-label="Permalink to &quot;4.1 给Project分类命名&quot;">​</a></h3><p>推荐命名规范：</p><ul><li><code>[领域] - [用途]</code>：如&quot;写作 - 公众号文章&quot;</li><li><code>[项目名] - [角色]</code>：如&quot;XX产品 - 测试助手&quot;</li></ul><h3 id="_4-2-定期更新知识库" tabindex="-1">4.2 定期更新知识库 <a class="header-anchor" href="#_4-2-定期更新知识库" aria-label="Permalink to &quot;4.2 定期更新知识库&quot;">​</a></h3><p>当你有新的重要文档时，及时添加到对应Project：</p><ul><li>每季度更新行业报告</li><li>项目有新进展时更新文档</li><li>品牌调性变化时更新系统提示</li></ul><h3 id="_4-3-额度使用技巧" tabindex="-1">4.3 额度使用技巧 <a class="header-anchor" href="#_4-3-额度使用技巧" aria-label="Permalink to &quot;4.3 额度使用技巧&quot;">​</a></h3><p>Projects内的对话和普通对话使用相同额度池。节省额度的方法：</p><ul><li>精简系统提示，避免过长的说明</li><li>知识库文件精选而非全上传</li><li>重要问题在Project里问，日常简单问题用普通对话</li></ul><hr><h2 id="五、projects常见问题" tabindex="-1">五、Projects常见问题 <a class="header-anchor" href="#五、projects常见问题" aria-label="Permalink to &quot;五、Projects常见问题&quot;">​</a></h2><p><strong>Q：Projects和普通对话有什么本质区别？</strong></p><p>普通对话没有持久记忆；Projects内Claude每次对话都能看到系统提示和知识库，相当于有了&quot;项目背景记忆&quot;。</p><p><strong>Q：免费版能用Projects吗？</strong></p><p>不能。Projects是Claude Pro及以上订阅用户专属功能。</p><p><strong>Q：Project内的对话会一直保存吗？</strong></p><p>是的，Project内的对话历史永久保存（普通对话只保留30天）。</p><p><strong>Q：可以和别人共享Project吗？</strong></p><p>个人版Projects暂不支持共享；企业版（Claude for Enterprise）支持团队共享。</p><div class="wechat-cta"><div class="text"><h3>🔥 开通Claude Pro，解锁Projects长期记忆功能</h3><p>添加客服微信 <strong>Luv12203</strong>，5分钟代充Claude Pro，即刻创建你的第一个Project。</p></div><img src="https://www.snakegpt.vip/file/system/others/1765252538015_mx1y.png" alt="Claude代充客服微信二维码 Luv12203"></div><p><strong>相关阅读</strong>：</p><ul><li><a href="/news/grok-42-multi-agent-practical-guide-2026">Claude多Agent协作实战教程</a></li><li><a href="/news/claude-code-guide-2026">Claude Code使用指南（开发者必看）</a></li><li><a href="/news/supergrok-subscription-plan-comparison-guide-2026">Claude Pro/Max/Max20x三档怎么选</a></li></ul>`,65)])])}const g=a(o,[["render",r]]);export{h as __pageData,g as default};
